            if 0 <= ni < n and 0 <= nj < n:
                neighbors.append((ni, nj))
        return neighbors

    # dp[i][j] = best path of length 'step' starting at (i,j)
    # To avoid memory issues, store only the first element and pointer to next
    # Instead, use the observation that paths stabilize

    # Store current best paths but cap representation
    # Use tuples for comparison efficiency

    current = {}
    for i in range(n):
        for j in range(n):
            current[(i,j)] = (grid[i][j],)

    prev_states = [current]

    for step in range(k-1):
        next_dp = {}
        for i in range(n):
            for j in range(n):
                best_next = None
